+    fn test_too_small_buffer_for_exe() {
+        // Only argc, no exe path bytes at all (no NUL terminator)
+        let mut buf = Vec::new();
+        buf.extend_from_slice(&1i32.to_ne_bytes());
+        // No exe path follows — consume_cstr should fail since there's no NUL
